package com.cho2hand.marketplace.entity.comment;import jakarta.persistence.*;import java.time.Instant;
@Entity@Table(name="comments")public class Comment{@Id@GeneratedValue(strategy=GenerationType.IDENTITY)@Column(name="comment_id")private Long id;@Column(name="listing_id")private Long listingId;@Column(name="author_user_id")private Long authorUserId;@Column(name="parent_comment_id")private Long parentCommentId;private String body;private String status;@Column(name="created_at")private Instant createdAt;@Column(name="updated_at")private Instant updatedAt;@PrePersist void created(){createdAt=updatedAt=Instant.now();status="VISIBLE";}@PreUpdate void updated(){updatedAt=Instant.now();}public Long getId(){return id;}public Long getListingId(){return listingId;}public void setListingId(Long v){listingId=v;}public Long getAuthorUserId(){return authorUserId;}public void setAuthorUserId(Long v){authorUserId=v;}public String getBody(){return body;}public void setBody(String v){body=v;}public Instant getCreatedAt(){return createdAt;}}
